rpgSnippet:
P GetDescription  B
D GetDescription  PI
C*****************************************************************
  HGRP = *Blanks;
  TEIL = *Blanks;
  SCOD = *Blanks;
  //TEILE-NR.
  If G7307A <> *Blanks;
     Chain G7307A ITLSMF3;
     If Not %Found(ITLSMF3) Or AFCODE <> 'L' OR SDCPRT = 'Y';
        If G7307A <> *Blanks;
           TEIL = 'Fremdteil';
        EndIf;
     Else;
        If %Found(ITLSMF3);
           TEIL = SDESC;
        EndIf;
     EndIf;
  EndIf;
  //Hauptgruppe
  If G7308A <> *Blanks;
     Chain (%Dec(G7308A:2:0):'  ') S3F018;
     If %Found(S3F018);
        HGRP = DESCYY;
     EndIf;
  EndIf;
  //Steuercode
  If G7314A = *Blanks;
     G7318A = 100;
     G7319A = 100;
     G7320A = 100;
  Else;
     Chain G7314A S3F085;
     If %Found(S3F085);
        If DFTAWF = 0;
           G7318A = DMCPWF;
           G7319A = DLCPWF;
           G7320A = DSCPWF;
        Else;
           *In84 = *Off;
           KLMAT = DFTAWF;
           SetLl KEY084 S3F084;
           Read S3F084;
           If Not %Eof(S3F084) And DFTAWE <> KLMAT;
              *In84 = *On;
           EndIf;
           If *In84;
              G7318A = 0;
              G7319A = 0;
              G7320A = 0;
           Else;
              G7318A =  DMCPWE;
              G7319A =  DLCPWE;
              G7320A =  DSCPWE;
           EndIf;
        EndIf;
     EndIf;
  EndIf;
  //EPS
  If A_EPS <> *Blanks;
     D_EPS = getEpsTitle(A_EPS);
     EpsType = getEpsType(A_EPS:G71060);
     Select;
     When EpsType = '1';
        G7318A = getEpsComp(A_EPS:G71060);
        G7319A = G7318A;
        G7320A = G7318A;
     When EpsType = '2';
        G7318A = getEpsComp(A_EPS:G71060);
        G7319A = 0;
        G7320A = 0;
     When EpsType = '3';
        G7318A = 0;
        G7319A = getEpsComp(A_EPS:G71060);
        G7320A = G7319A;
     When D_Eps = *Blanks;
        SetLl (PKZ:G71010:G71020:STORNO:G71030:G_BEREICH:G_WETE:'Q4')
              HSAHTPF;
        ReadE (PKZ:G71010:G71020:STORNO:G71030:G_BEREICH:G_WETE:'Q4')
              HSAHTPF;
        Dow Not %Eof(HSAHTPF);
           If AHT470 <> *Blanks;
              G7318A = 100 - AHT480;
            EndIf;
           ReadE (PKZ:G71010:G71020:STORNO:G71030:G_BEREICH:G_WETE:'Q4')
                 HSAHTPF;
        EndDo;
        SetLl (PKZ:G71010:G71020:STORNO:G71030:G_BEREICH:G_WETE:'Q4')
              HSAHWPF;
        ReadE (PKZ:G71010:G71020:STORNO:G71030:G_BEREICH:G_WETE:'Q4')
              HSAHWPF;
        Dow Not %Eof(HSAHWPF);
           If AHW330 <> *Blanks;
              G7319A = 100 - AHW340;
           EndIf;
           ReadE (PKZ:G71010:G71020:STORNO:G71030:G_BEREICH:G_WETE:'Q4')
                 HSAHWPF;
        EndDo;
        G7320A = 100;
     Other;
        G7318A = getEpsComp(A_EPS:G71060);
        G7319A = G7318A;
        G7320A = G7318A;
     EndSl;
  EndIf;
  If G7310A <> *Blanks;
     Chain (%Dec(G7310A:2:0)) S3F019;
     If %Found(S3F019);
        SCOD = DESCYZ;
     EndIf;
  EndIf;
  D_EPS = getEpsTitle(A_EPS);
  D_C1 = getCwpMsg('':C1:A_C1);
  D_C2 = getCwpMsg('':C2:A_C2);
  D_C3 = getCwpMsg('':C3:A_C3);
  D_C4 = getCwpMsg('':C4:A_C4);
  D_C5 = getCwpMsg('':C5:A_C5);
  D_C6 = getCwpMsg('':C6:A_C6);
P getDescription  E
